mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, base_data.* FROM ( SELECT inspection_type AS "inspectionType", target_type AS "targetType", TO_CHAR(inspection_date, 'YYYY-MM-DD') AS "inspectionDate", inspection_result AS "inspectionResult", inspection_reason AS "inspectionReason", risk_level AS "riskLevel" FROM (
) WHERE 1 = 1
AND inspection_date >= TO_DATE(#{search.startDate}, 'YYYY-MM-DD')
AND inspection_date >= ADD_MONTHS(TRUNC(SYSDATE + (9/24)), -6)
AND inspection_date < TO_DATE(#{search.endDate}, 'YYYY-MM-DD') + 1
AND risk_level = #{search.riskLevel}
AND ( UPPER(inspection_type) LIKE UPPER('%' || #{search.equipKeyword} || '%') OR UPPER(target_type) LIKE UPPER('%' || #{search.equipKeyword} || '%') OR UPPER(inspection_result) LIKE UPPER('%' || #{search.equipKeyword} || '%') OR UPPER(inspection_reason) LIKE UPPER('%' || #{search.equipKeyword} || '%') )
ORDER BY inspection_date DESC ) base_data WHERE ROWNUM <= #{page.endRow} ) WHERE rnum >= #{page.startRow}

SELECT risk_level AS "riskLevel", COUNT(*) AS "riskCount" FROM (
)
GROUP BY risk_level ORDER BY CASE risk_level WHEN 'RISK' THEN 1 WHEN 'WARNING' THEN 2 WHEN 'NORMAL' THEN 3 ELSE 4 END

SELECT * FROM ( SELECT inspection_type AS "inspectionType", target_type AS "targetType", TO_NUMBER(TO_CHAR(inspection_date, 'MM')) AS "inspectionMonth", TO_NUMBER(TO_CHAR(inspection_date, 'D')) AS "inspectionWeekday" FROM (
)
ORDER BY CASE risk_level WHEN 'RISK' THEN 1 WHEN 'WARNING' THEN 2 WHEN 'NORMAL' THEN 3 ELSE 4 END, inspection_date DESC ) WHERE ROWNUM = 1
